import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function rn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function np(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"np",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function rpn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rpn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  // === RN QUESTIONS ===
  rn("NCLEX-RN","Cardiovascular",3,"A client post-coronary artery bypass graft is at risk for atrial fibrillation. The nurse knows this is most common on which postoperative day?",["Day 1","Day 2-3","Day 7-10","Day 14"],1,"Post-CABG AF peaks on postoperative days 2-3 due to atrial inflammation, pericarditis, electrolyte imbalances, and autonomic changes. Beta-blocker prophylaxis reduces incidence. Rate control and anticoagulation are managed per protocol."),
  rn("NCLEX-RN","Cardiovascular",3,"A client has a troponin I level of 2.5 ng/mL. The nurse should interpret this as:",["Normal finding","Elevated and indicative of myocardial injury or infarction","Borderline requiring repeat in 1 week","A liver function marker"],1,"Troponin I > 0.04 ng/mL (or above the 99th percentile) indicates myocardial injury. A level of 2.5 is significantly elevated, consistent with acute MI. Serial troponins (at 0, 3, and 6 hours) establish the pattern of rise and fall diagnostic of acute MI."),
  rn("RN-CAT","Cardiovascular",3,"A client with mitral stenosis has which characteristic murmur on auscultation?",["Systolic crescendo-decrescendo at the aortic area","Low-pitched diastolic rumble at the apex (best heard with bell)","Holosystolic murmur at the left sternal border","Midsystolic click"],1,"Mitral stenosis produces a low-pitched diastolic rumble best heard at the apex with the bell of the stethoscope in the left lateral decubitus position. Opening snap precedes the murmur. Most commonly caused by rheumatic heart disease."),
  rn("NCLEX-RN","Respiratory",3,"A client with a massive pleural effusion has dyspnea and decreased breath sounds on the left side. The nurse should position the client with:",["The affected (left) side down","The affected (left) side up to maximize ventilation of the unaffected lung","Flat in bed","Prone"],1,"Positioning with the affected side up (good lung down) maximizes ventilation-perfusion matching by gravitating blood flow to the dependent, well-ventilated lung while relieving pressure from the effusion on the mediastinum."),
  rn("NCLEX-RN","Respiratory",3,"A client with severe asthma in the emergency department has a 'silent chest' on auscultation. The nurse recognizes this as:",["Improvement in the asthma attack","A life-threatening finding indicating complete airway obstruction","Normal between asthma attacks","A sign that the bronchodilator is working"],1,"Silent chest during an asthma attack is ominous - it indicates such severe bronchoconstriction that no air is moving through the airways. This is impending respiratory failure requiring immediate intubation preparation and aggressive bronchodilator/corticosteroid therapy."),
  rn("RN-CAT","Respiratory",4,"A client on mechanical ventilation with ARDS has a P/F ratio of 85. This indicates:",["Mild ARDS","Moderate ARDS","Severe ARDS requiring prone positioning consideration","Normal oxygenation"],2,"Berlin criteria P/F ratios: mild ARDS 200-300, moderate 100-200, severe < 100. P/F ratio of 85 indicates severe ARDS. Interventions include lung-protective ventilation, prone positioning (12-16 hours/day), neuromuscular blockade, and possibly ECMO."),
  rn("NCLEX-RN","Neurological",3,"A client with a subarachnoid hemorrhage is at highest risk for which complication between days 4-14?",["Rebleeding only","Cerebral vasospasm causing delayed cerebral ischemia","Wound infection","Hydrocephalus resolution"],1,"Cerebral vasospasm peaks at days 4-14 post-SAH, causing delayed cerebral ischemia and potential stroke. Triple-H therapy (hypertension, hypervolemia, hemodilution - now modified to euvolemia and induced hypertension) and nimodipine prevent and treat vasospasm."),
  rn("NCLEX-RN","Neurological",3,"A client with bacterial meningitis is placed on droplet precautions. The nurse should wear:",["N95 respirator","Surgical mask within 6 feet of the client","No mask needed after antibiotics are started","Full face shield at all times"],1,"Bacterial meningitis (N. meningitidis) requires droplet precautions: surgical mask within 3-6 feet of the client. Precautions can be discontinued after 24 hours of effective antibiotic therapy. Close contacts should receive chemoprophylaxis (rifampin, ciprofloxacin, or ceftriaxone)."),
  rn("RN-CAT","Neurological",3,"A client with acute ischemic stroke has a door-to-needle time goal for tPA administration of:",["Less than 2 hours","Less than 60 minutes","Less than 30 minutes","Less than 4.5 hours"],1,"AHA/ASA recommends door-to-needle time < 60 minutes for IV tPA. Stroke teams use rapid assessment protocols including CT scan, neurological examination (NIHSS), labs, and consent. Time is brain - each minute of ischemia destroys approximately 1.9 million neurons."),
  rn("NCLEX-RN","Endocrine",3,"A client with syndrome of inappropriate ADH (SIADH) has a serum sodium of 122 mEq/L. The nurse should:",["Administer IV normal saline rapidly","Restrict fluids and monitor serum sodium closely","Encourage oral fluid intake","Administer IV dextrose 5%"],1,"SIADH causes dilutional hyponatremia from excess water retention. Primary treatment is fluid restriction (500-1000 mL/day). Hypertonic saline (3%) may be needed for severe symptomatic hyponatremia. Rapid correction risks osmotic demyelination syndrome."),
  rn("NCLEX-RN","Endocrine",3,"A client with diabetes insipidus has a urine specific gravity of 1.001 and serum sodium of 152 mEq/L. This indicates:",["Normal hydration status","Excessive dilute urine with hypernatremia from water loss","Concentrated urine","SIADH"],1,"DI causes excretion of large volumes of very dilute urine (specific gravity < 1.005) leading to dehydration and hypernatremia. Treatment: adequate fluid replacement and desmopressin (DDAVP) for central DI. Nephrogenic DI may respond to thiazide diuretics."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with acute variceal bleeding should receive which medication to reduce portal pressure?",["Propranolol as first-line","Octreotide or vasopressin IV to reduce splanchnic blood flow","IV furosemide","Oral lactulose"],1,"Acute variceal bleeding management: IV octreotide (or terlipressin) reduces portal pressure by splanchnic vasoconstriction, IV PPI, emergent endoscopic band ligation, antibiotics prophylaxis (ceftriaxone), and blood product resuscitation."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with gastric outlet obstruction from peptic ulcer disease develops which electrolyte imbalance from prolonged vomiting?",["Hyperkalemia and metabolic acidosis","Hypochloremic, hypokalemic metabolic alkalosis","Hypernatremia and respiratory alkalosis","No electrolyte changes"],1,"Gastric outlet obstruction causes loss of HCl-rich gastric contents. This leads to hypochloremia, hypokalemia (renal K+ wasting to compensate for alkalosis), and metabolic alkalosis. The kidneys retain bicarbonate paradoxically due to chloride depletion."),
  rn("RN-CAT","Gastrointestinal",4,"A client post-liver transplant develops increasing AST and ALT with bilirubin elevation on day 7. The nurse suspects:",["Normal post-surgical healing","Acute cellular rejection requiring biopsy and increased immunosuppression","Bile duct obstruction","Drug toxicity only"],1,"Rising liver enzymes and bilirubin 5-10 days post-transplant suggest acute cellular rejection. Liver biopsy confirms the diagnosis (portal inflammation, bile duct damage). Treatment is pulse IV methylprednisolone or OKT3/ATG for steroid-resistant rejection."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving vancomycin should have trough levels drawn:",["Immediately after the infusion","30 minutes before the next scheduled dose","4 hours after the infusion","At any time during the dosing interval"],1,"Vancomycin trough levels are drawn 30 minutes BEFORE the next dose (at the lowest drug concentration). Target troughs are 15-20 mcg/mL for serious infections (bacteremia, endocarditis, osteomyelitis, meningitis). Levels guide dose adjustments."),
  rn("NCLEX-RN","Pharmacology",3,"A client is started on a direct oral anticoagulant (DOAC) such as rivaroxaban. The advantage over warfarin includes:",["More drug interactions","Fixed dosing without routine INR monitoring","Lower cost in all cases","Easier to reverse in emergencies"],1,"DOACs offer fixed dosing, no routine lab monitoring, fewer drug/food interactions, and rapid onset of action. Reversal agents exist (idarucizumab for dabigatran, andexanet alfa for factor Xa inhibitors). However, they are more expensive and have renal clearance considerations."),
  rn("RN-CAT","Pharmacology",4,"A client receiving milrinone for decompensated heart failure should be monitored for:",["Hypertension","Hypotension and arrhythmias (milrinone is an inodilator)","Bronchospasm","Hepatotoxicity"],1,"Milrinone is a phosphodiesterase III inhibitor (inodilator): increases contractility while decreasing SVR and PVR. Side effects include hypotension (vasodilation), arrhythmias (increased cAMP), and thrombocytopenia. Continuous hemodynamic monitoring is required."),
  rn("NCLEX-RN","Mental Health",3,"A client with alcohol use disorder who has been abstinent for 3 months should be offered which evidence-based medication for relapse prevention?",["Benzodiazepines","Naltrexone or acamprosate","Disulfiram as first-line in all cases","Haloperidol"],1,"Naltrexone (opioid antagonist) reduces alcohol craving and consumption. Acamprosate restores glutamate/GABA balance disrupted by chronic alcohol use. Both are FDA-approved for alcohol relapse prevention. Disulfiram creates aversive effects with alcohol but requires high compliance."),
  rn("NCLEX-RN","Mental Health",3,"A nurse documents that a client with schizophrenia has 'word salad.' This term describes:",["Organized but repetitive speech","Incoherent, jumbled speech with no logical connection between words","Speaking in rhymes","Repeating what others say"],1,"Word salad is extremely disorganized speech with no discernible meaning or logical connection between words. It represents severe thought disorder in schizophrenia. Other speech abnormalities include neologisms (invented words), clang associations (rhyming), and echolalia (repetition)."),
  rn("NCLEX-RN","Pediatrics",3,"A child with acute lymphoblastic leukemia develops tumor lysis syndrome after chemotherapy. The nurse should anticipate:",["Hypocalcemia, hyperkalemia, hyperuricemia, and hyperphosphatemia","Hypercalcemia and hypokalemia","Only mild electrolyte changes","No metabolic changes after chemotherapy"],0,"TLS occurs when rapid cancer cell destruction releases intracellular contents: potassium (hyperkalemia), phosphorus (hyperphosphatemia with secondary hypocalcemia), uric acid (hyperuricemia, nephropathy). Prevention: aggressive hydration, allopurinol or rasburicase, monitoring."),
  rn("NCLEX-RN","Pediatrics",3,"A child with tetralogy of Fallot has a 'tet spell' (hypercyanotic episode). The nurse should:",["Lay the child flat and administer oxygen","Place the child in knee-chest position and administer morphine and oxygen","Start CPR immediately","Administer epinephrine"],1,"Knee-chest position increases SVR, reducing right-to-left shunting and improving pulmonary blood flow. Morphine reduces infundibular spasm, oxygen improves saturation. Phenylephrine may be used for refractory episodes. IV fluids support preload."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with ectopic pregnancy has an hCG level that is not doubling appropriately. The nurse should prepare the client for:",["Normal pregnancy management","Methotrexate therapy or possible surgical intervention","Bed rest and observation only","Immediate cesarean delivery"],1,"Ectopic pregnancy with abnormal hCG rise (< 66% increase in 48 hours) requires treatment: methotrexate (medical, if unruptured and < 3.5 cm) or salpingostomy/salpingectomy (surgical, if ruptured or large). hCG levels are monitored until negative."),
  rn("NCLEX-RN","Maternal/Newborn",3,"Group B streptococcus prophylaxis during labor is indicated when:",["All women should receive prophylaxis","GBS-positive screen at 36-37 weeks, previous infant with GBS disease, or GBS bacteriuria during pregnancy","Only for women with fever during labor","Only for cesarean deliveries"],1,"Intrapartum antibiotic prophylaxis (IV penicillin G or ampicillin) prevents neonatal early-onset GBS disease. Indications: positive GBS vaginal/rectal screen at 36-37 weeks, GBS bacteriuria, previous infant with GBS disease, or unknown status with risk factors."),
  rn("NCLEX-RN","Renal",3,"A client with polycystic kidney disease has bilateral flank pain and a family history of brain aneurysms. The nurse should:",["Focus on kidney management only","Screen for intracranial aneurysms as there is an association between ADPKD and cerebral aneurysms","Order a cardiac catheterization","Refer for genetic testing only"],1,"ADPKD is associated with cerebral aneurysms (5-10% of patients). MRA screening is recommended for patients with family history of brain aneurysm or subarachnoid hemorrhage. Ruptured cerebral aneurysm is the most serious extrarenal manifestation."),
  rn("NCLEX-RN","Hematological",3,"A client on therapeutic anticoagulation develops heparin-induced thrombocytopenia (HIT). The nurse should:",["Increase the heparin dose","Stop all heparin products immediately and switch to a direct thrombin inhibitor","Continue heparin and add platelets","Administer protamine sulfate"],1,"HIT is an immune-mediated prothrombotic condition requiring immediate heparin cessation (including flushes). Switch to a direct thrombin inhibitor (argatroban, bivalirudin). Do NOT give platelets (fuel thrombosis). Test for HIT antibodies. Warfarin is started only after platelet recovery."),
  rn("NCLEX-RN","Immunological",3,"A client receiving a kidney transplant from a living donor is started on triple immunosuppressive therapy. This typically includes:",["Only one immunosuppressant medication","Calcineurin inhibitor (tacrolimus), antiproliferative (mycophenolate), and corticosteroid","Three different antibiotics","Chemotherapy agents"],1,"Standard triple immunosuppression post-transplant: tacrolimus (calcineurin inhibitor - prevents T-cell activation), mycophenolate mofetil (prevents lymphocyte proliferation), and prednisone (anti-inflammatory). Drug levels and side effects require close monitoring."),
  rn("RN-CAT","Critical Care",4,"A client with severe traumatic brain injury has intracranial pressure of 30 mmHg. The cerebral perfusion pressure calculation requires:",["ICP and heart rate","MAP minus ICP (CPP = MAP - ICP)","Systolic blood pressure only","Cardiac output measurement"],1,"CPP = MAP - ICP. Normal CPP is 60-70 mmHg minimum. With ICP of 30 and target CPP > 60, MAP must be maintained > 90 mmHg. ICP management includes osmotic therapy (mannitol, hypertonic saline), sedation, CSF drainage, and possible decompressive craniectomy."),
  rn("RN-CAT","Critical Care",3,"A client with acute respiratory failure requires intubation. The nurse should ensure the following is verified after intubation:",["Only chest rise observation","End-tidal CO2 confirmation (capnography), bilateral breath sounds, and chest X-ray","Heart rate monitoring only","Blood pressure measurement"],1,"Post-intubation verification: continuous end-tidal CO2 (most reliable real-time confirmation), bilateral breath sounds (rule out right mainstem intubation), chest X-ray (tube position 2-4 cm above carina), and SpO2 monitoring. Capnography is the gold standard."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with new-onset heart failure has a BNP of 950 pg/mL. The nurse interprets this as:",["Normal heart function","Consistent with heart failure (elevated BNP indicates ventricular stretch)","Renal failure marker","Normal aging finding"],1,"BNP (B-type natriuretic peptide) is released from ventricles under stretch. BNP > 100 pg/mL suggests heart failure (higher values correlate with severity). NT-proBNP > 300 has similar significance. Used for diagnosis and monitoring treatment response."),
  rn("NCLEX-RN","Respiratory",3,"A client with bronchiectasis requires which long-term management approach?",["Short courses of antibiotics during exacerbations only","Daily airway clearance therapy, prompt antibiotic treatment of infections, and possible long-term macrolide therapy","Inhaled corticosteroids as sole therapy","Surgical resection as first-line treatment"],1,"Bronchiectasis management includes daily airway clearance (CPT, flutter valve, HFCWO), prompt treatment of infections with appropriate antibiotics, low-dose macrolide for frequent exacerbations (anti-inflammatory effect), and pneumococcal/influenza vaccination."),
  rn("NCLEX-RN","Neurological",3,"A client who had a lumbar puncture 8 hours ago develops a severe positional headache. The nurse should:",["Administer NSAIDs and encourage ambulation","Encourage flat positioning, hydration, caffeine intake, and anticipate possible blood patch","Elevate the head of bed for comfort","Perform another lumbar puncture"],1,"Post-LP headache results from CSF leak through the dural puncture site. Flat positioning reduces pressure differential. IV/oral caffeine constricts cerebral blood vessels. Epidural blood patch (injection of autologous blood near the puncture site) is definitive treatment for persistent headaches."),
  rn("NCLEX-RN","Endocrine",3,"A client with hyperglycemic hyperosmolar state (HHS) has a serum osmolality of 340 mOsm/kg. The nurse should anticipate:",["Rapid insulin bolus","Aggressive isotonic fluid resuscitation first, then insulin drip","Oral glucose tablets","Bicarbonate infusion"],1,"HHS (glucose often > 600, osmolality > 320, minimal ketones) causes severe dehydration. Treatment priorities: aggressive IV fluid resuscitation (isotonic NS initially, then switch to 0.45% NS when hemodynamically stable), low-dose insulin drip after hydration initiated, and electrolyte replacement."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with inflammatory bowel disease is started on infliximab. The nurse should screen for which infection before starting therapy?",["HIV","Latent tuberculosis (TB skin test or IGRA before starting anti-TNF therapy)","Hepatitis A","Streptococcal pharyngitis"],1,"Anti-TNF agents (infliximab, adalimumab) increase risk of reactivation TB. Screening with TST or IGRA is mandatory before initiation. If latent TB is found, treatment should begin before starting anti-TNF therapy. Also screen for hepatitis B."),
  rn("NCLEX-RN","Pharmacology",3,"A client on metformin is scheduled for a contrast CT scan. The nurse should:",["Continue metformin without interruption","Hold metformin on the day of and for 48 hours after the contrast study","Increase the metformin dose","Switch to insulin permanently"],1,"Metformin is held before and 48 hours after IV contrast because contrast-induced nephropathy can impair metformin clearance, increasing lactic acidosis risk. Renal function should be confirmed as adequate before restarting metformin."),
  rn("NCLEX-RN","Mental Health",3,"A client with acute stress disorder has symptoms that have persisted for 2 weeks after a traumatic event. The nurse should understand that if symptoms persist beyond:",["1 month, the diagnosis changes to PTSD","2 months, the diagnosis changes","6 months, the diagnosis changes","No timeline distinction exists"],0,"Acute stress disorder: symptoms for 3 days to 1 month post-trauma. If symptoms persist beyond 1 month, the diagnosis changes to PTSD. Early CBT with exposure therapy for ASD can prevent PTSD development."),
  rn("NCLEX-RN","Pediatrics",3,"A premature infant at 33 weeks gestation needs a hearing screen because prematurity increases risk for:",["No hearing issues","Sensorineural hearing loss from ototoxic medications and hyperbilirubinemia","Conductive hearing loss only","Temporary hearing changes"],1,"Premature infants have increased sensorineural hearing loss risk from ototoxic medications (aminoglycosides, furosemide), hyperbilirubinemia, hypoxia, and NICU noise. Universal newborn hearing screening identifies impairment early for intervention during the critical language development period."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client in the fourth stage of labor (first 1-2 hours postpartum) should be monitored for:",["Only emotional bonding with the infant","Postpartum hemorrhage through frequent vital signs and fundal assessments","Resumption of normal diet only","Ambulation tolerance"],1,"The first 1-2 hours postpartum are highest risk for hemorrhage. Monitor vital signs every 15 minutes, fundal firmness and position, lochia amount and character, perineal integrity, and bladder distension (full bladder displaces uterus and prevents contraction)."),
  rn("NCLEX-RN","Renal",3,"A client with chronic kidney disease should receive which form of vitamin D?",["Over-the-counter vitamin D3 as sole supplementation","Active vitamin D (calcitriol or paricalcitol) as the kidneys cannot convert inactive vitamin D","Vitamin D2 only","No vitamin D supplementation in CKD"],1,"CKD kidneys cannot convert 25-hydroxyvitamin D to active 1,25-dihydroxyvitamin D (calcitriol). Supplementation with active vitamin D analogues (calcitriol, paricalcitol, doxercalciferol) is necessary to manage calcium/phosphorus homeostasis and secondary hyperparathyroidism."),
  rn("NCLEX-RN","Infection Control",3,"Airborne precautions require:",["Surgical mask and private room","N95 respirator, private negative-pressure room with 6-12 air exchanges per hour","Gloves and gown only","Standard precautions with surgical mask"],1,"Airborne precautions (TB, measles, varicella, disseminated zoster): N95 respirator (fit-tested), negative-pressure room with 6-12 air exchanges/hour, door closed, and HEPA filtration. The patient wears a surgical mask during transport."),
  rn("NCLEX-RN","Hematological",3,"A client with aplastic anemia has pancytopenia. The nurse should prioritize:",["Iron supplementation alone","Infection prevention (neutropenia), bleeding precautions (thrombocytopenia), and energy conservation (anemia)","Aggressive physical therapy","High-protein diet as sole intervention"],1,"Pancytopenia requires addressing all three lineages: neutropenia (meticulous hand hygiene, avoid crowds, monitor temperature), thrombocytopenia (bleeding precautions, soft toothbrush, no aspirin), anemia (rest periods, oxygen as needed). Definitive treatment may include bone marrow transplant."),
  rn("NCLEX-RN","Immunological",3,"A client receiving rituximab for lymphoma develops progressive multifocal leukoencephalopathy (PML). The nurse should understand that:",["PML is a bacterial infection","PML is caused by JC virus reactivation and is often fatal with no specific treatment","PML is easily treated with antifungals","PML resolves spontaneously"],1,"PML is a devastating demyelinating brain disease caused by JC polyomavirus reactivation in immunosuppressed patients. It causes progressive neurological deficits and is often fatal. Treatment involves stopping immunosuppression and supportive care. No specific antiviral exists."),
  rn("RN-CAT","Cardiovascular",3,"A client with aortic dissection Type A (ascending aorta) requires:",["Medical management alone","Emergency surgical repair","Outpatient follow-up","Blood pressure elevation to increase perfusion"],1,"Stanford Type A aortic dissection (involving ascending aorta) is a surgical emergency with mortality of 1-2% per hour without treatment. Type B (descending only) is typically managed medically with aggressive BP and heart rate control."),
  rn("RN-CAT","Respiratory",3,"A client with acute exacerbation of idiopathic pulmonary fibrosis should receive:",["High-dose corticosteroids (though evidence is limited)","Aggressive bronchodilator therapy","Antibiotics alone","No treatment is available"],0,"Acute IPF exacerbations have high mortality (> 50%). Treatment options are limited and evidence is lacking. Empiric broad-spectrum antibiotics cover possible infection, high-dose corticosteroids are often tried, and supportive care with oxygen. Lung transplant evaluation should be considered."),
  rn("NCLEX-RN","Neurological",3,"A client with increased ICP should have which medication available for emergent use?",["Acetaminophen","Mannitol (osmotic diuretic) for rapid ICP reduction","Furosemide as sole agent","Dexamethasone for acute herniation"],1,"IV mannitol (0.25-1g/kg) rapidly reduces ICP through osmotic diuresis and cerebral vasoconstriction. Works within 15-30 minutes. 3% hypertonic saline is an alternative. Monitor serum osmolality (hold if > 320 mOsm/kg), electrolytes, and volume status."),
  rn("NCLEX-RN","Endocrine",3,"A client with type 1 diabetes should be taught that during illness (sick day rules):",["Stop all insulin to prevent hypoglycemia","Never stop insulin; increase monitoring, maintain hydration, and may need more insulin","Reduce insulin by half during illness","Switch to oral hypoglycemics during illness"],1,"Sick day rules for T1DM: NEVER stop insulin (illness increases glucose through stress hormones), monitor glucose every 2-4 hours, check ketones, maintain hydration with clear fluids, consume easily digestible carbs if possible, and contact provider if unable to eat or if ketones are positive."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with hepatorenal syndrome has worsening renal function despite adequate intravascular volume. The nurse should understand that:",["This is unrelated to liver disease","Hepatorenal syndrome is functional renal failure caused by severe splanchnic vasodilation in advanced liver disease","Dialysis will cure the condition","The condition responds well to NSAIDs"],1,"Hepatorenal syndrome occurs in advanced cirrhosis when severe splanchnic vasodilation causes renal vasoconstriction and functional renal failure. Treatment: vasoconstrictors (midodrine + octreotide or terlipressin) + albumin. Definitive treatment is liver transplant."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving gentamicin should have which laboratory values monitored?",["Liver function tests","Peak and trough drug levels, BUN, creatinine, and audiometry","Coagulation studies","Thyroid function tests"],1,"Aminoglycosides (gentamicin) are nephrotoxic and ototoxic. Monitor: trough levels (< 2 mcg/mL) before dosing, BUN/creatinine for nephrotoxicity, and audiometry for ototoxicity (hearing loss, tinnitus, vestibular dysfunction). Once-daily dosing reduces nephrotoxicity."),
  rn("NCLEX-RN","Mental Health",3,"A client with obsessive-compulsive disorder washes their hands until they bleed. The nurse understands the hand washing serves to:",["Improve hygiene","Temporarily reduce the intense anxiety produced by obsessive thoughts","Express anger","Seek attention from staff"],1,"Compulsions are repetitive behaviors performed to reduce anxiety generated by obsessive thoughts. The relief is temporary, reinforcing the compulsive cycle. ERP therapy breaks this cycle by exposing the client to anxiety triggers without allowing the compulsive response."),
  rn("NCLEX-RN","Pediatrics",3,"A child with cystic fibrosis has a positive sweat chloride test. The nurse knows the diagnostic value is:",["Chloride > 30 mEq/L","Chloride >= 60 mEq/L on two separate occasions","Chloride > 100 mEq/L","Any positive chloride test"],1,"Sweat chloride >= 60 mEq/L on two occasions is diagnostic for CF. Values 30-59 are intermediate, requiring repeat testing and genetic testing. < 30 mEq/L is normal. The quantitative pilocarpine iontophoresis (Gibson-Cooke) test is the gold standard."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client in labor has a fetal heart rate baseline of 180 bpm. The nurse should:",["Document as a normal variation","Evaluate for fetal tachycardia causes including maternal fever, dehydration, and medications","Increase oxytocin","Prepare for immediate delivery"],1,"Fetal tachycardia (> 160 bpm) causes include maternal fever, dehydration, medications (terbutaline, atropine), fetal anemia, infection (chorioamnionitis), and fetal distress. The nurse identifies and treats the underlying cause while monitoring fetal status."),
  rn("NCLEX-RN","Renal",3,"A client with end-stage renal disease develops pericarditis. The nurse should anticipate:",["Antibiotic therapy","Intensified dialysis to remove uremic toxins","Pericardiocentesis as first-line","Oral NSAID therapy only"],1,"Uremic pericarditis in ESRD is caused by toxic metabolite accumulation. Treatment is intensified dialysis (daily sessions) without heparin (to prevent hemorrhagic pericardial effusion). If ineffective, pericardial window or pericardiectomy may be needed."),
  rn("NCLEX-RN","Hematological",3,"A client with von Willebrand disease should be taught to avoid:",["All exercise","Aspirin and NSAIDs which impair platelet function","Leafy green vegetables","Dairy products"],1,"Von Willebrand disease impairs platelet adhesion. Aspirin and NSAIDs further impair platelet function, significantly increasing bleeding risk. DDAVP (stimulates VWF release) is first-line treatment for type 1. Aminocaproic acid may be used for mucosal bleeding."),
  rn("RN-CAT","Critical Care",4,"A client on ECMO develops differential hypoxemia (upper body SpO2 > lower body SpO2 on VA ECMO). The nurse should understand this suggests:",["Normal ECMO function","Native cardiac function is recovering but lungs remain compromised","ECMO circuit failure","Volume overload"],1,"Differential hypoxemia (Harlequin syndrome) on VA ECMO occurs when native cardiac function improves and ejects poorly oxygenated blood from diseased lungs to the proximal aorta, while ECMO provides oxygenated blood distally. May require VV ECMO addition or transition."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with Wolff-Parkinson-White syndrome has an accessory pathway identified on ECG as:",["ST elevation in leads V1-V4","Delta wave (slurred upstroke of QRS complex) with short PR interval","Peaked T waves","U waves"],1,"WPW ECG findings: short PR interval (< 0.12 seconds), delta wave (slurred QRS upstroke from pre-excitation), and wide QRS complex. These findings result from ventricular pre-excitation through the accessory pathway (bundle of Kent). Ablation is curative."),
  rn("NCLEX-RN","Respiratory",3,"A client with a hemothorax should have the chest tube placed in which intercostal space?",["2nd intercostal space, midclavicular line","5th-6th intercostal space, midaxillary line (lateral approach for fluid drainage)","8th intercostal space, posterior axillary line","1st intercostal space, anterior"],1,"Chest tubes for fluid drainage (hemothorax, effusion) are placed in the 5th-6th intercostal space at the midaxillary line, directed posteriorly and inferiorly. Pneumothorax tubes may be placed at the 2nd intercostal space, midclavicular, directed superiorly."),
  rn("NCLEX-RN","Neurological",3,"A client with temporal lobe epilepsy may exhibit which type of seizure activity?",["Tonic-clonic movements only","Automatisms such as lip smacking, chewing, and fumbling movements","Absence seizures exclusively","Drop attacks"],1,"Temporal lobe seizures (focal aware or impaired awareness) characteristically involve automatisms: lip smacking, chewing, hand fumbling, and repetitive movements. Aura may include deja vu, epigastric rising sensation, or olfactory hallucinations."),

  // === NP QUESTIONS ===
  np("AANP","Cardiovascular",3,"A patient with stage 2 hypertension (BP 150/95) should be started on:",["Lifestyle modifications alone for 6 months","Two antihypertensive medications from different classes","One medication at the lowest dose","Three medications simultaneously"],1,"ACC/AHA 2017: Stage 2 hypertension (>= 140/90) should be started on 2 antihypertensive medications from different classes (typically thiazide + ACEi/ARB or CCB + ACEi/ARB). Single-drug therapy is insufficient for stage 2."),
  np("AANP","Respiratory",3,"A patient with chronic cough produces yellow-green sputum. Before prescribing antibiotics, the NP should:",["Prescribe antibiotics immediately","Obtain a sputum culture and consider that yellow-green sputum alone does not indicate bacterial infection","Start a broad-spectrum antibiotic empirically","Order CT of the chest"],1,"Purulent sputum color correlates poorly with bacterial infection. Eosinophilic inflammation (asthma) can produce green sputum. Obtain culture, consider other causes (GERD, postnasal drip, asthma), and only prescribe antibiotics if bacterial infection is confirmed or highly likely."),
  np("NP-CAT","Endocrine",3,"A patient with a thyroid nodule > 1 cm with suspicious ultrasound features should have:",["Observation only","Fine needle aspiration biopsy","Immediate thyroidectomy","Radioactive iodine scan as first step"],1,"Thyroid nodules > 1 cm with suspicious features (hypoechoic, microcalcifications, irregular margins, taller-than-wide shape) require FNA biopsy per Bethesda classification. Risk of malignancy ranges from 5-99% depending on cytology results."),
  np("AANP","Gastrointestinal",3,"A patient with irritable bowel syndrome with diarrhea (IBS-D) should be offered first-line treatment with:",["Opioid analgesics","Low FODMAP diet, fiber supplementation, and antispasmodics","Corticosteroids","Proton pump inhibitors"],1,"IBS-D management: low FODMAP diet (reduces fermentable carbohydrates), soluble fiber (psyllium), antispasmodics (hyoscyamine, dicyclomine), and for moderate-severe cases, eluxadoline or rifaximin. TCAs may help with pain and diarrhea."),
  np("AANP","Neurological",3,"A patient with new-onset cluster headache should be treated acutely with:",["Oral sumatriptan","High-flow oxygen (12-15 L/min) and/or subcutaneous sumatriptan","Opioid analgesics","Acetaminophen and rest"],1,"Cluster headache acute treatment: high-flow 100% oxygen (12-15 L/min via non-rebreather for 15-20 minutes) and/or subcutaneous sumatriptan 6mg. Oral medications are too slow for cluster attacks. Preventive therapy includes verapamil as first-line."),
  np("NP-CAT","Pharmacology",3,"A patient on lithium has a level of 2.0 mEq/L. The NP should:",["Continue the current dose","Recognize this as toxic, hold lithium, and monitor closely","Increase the dose for better therapeutic effect","Add valproic acid"],1,"Therapeutic lithium level is 0.6-1.2 mEq/L. Level of 2.0 is toxic causing nausea, vomiting, tremor, confusion, and potentially seizures, renal failure, and coma. Hold lithium, hydrate, monitor electrolytes and renal function. Dialysis may be needed for severe toxicity."),
  np("AANP","Mental Health",3,"A patient with ADHD in adulthood should be treated first-line with:",["Benzodiazepines","Stimulant medication (methylphenidate or amphetamine-based)","Antipsychotics","SSRIs"],1,"Stimulants (methylphenidate, amphetamine salts) are first-line for adult ADHD with 70-80% response rate. Non-stimulants (atomoxetine, bupropion) are alternatives for substance abuse history, anxiety, or stimulant intolerance. Comprehensive treatment includes behavioral strategies."),
  np("AANP","Dermatology",3,"A patient with a rapidly growing pigmented lesion with asymmetry, irregular borders, and color variation should have:",["Shave biopsy","Excisional biopsy with narrow margins to assess Breslow depth","Punch biopsy","Observation for 3 months"],1,"Suspected melanoma requires excisional biopsy with 1-3mm margins to provide full-thickness specimen for accurate Breslow depth measurement. Shave biopsy may transect the tumor, preventing accurate depth assessment. Wide excision is performed after diagnosis."),
  np("NP-CAT","Musculoskeletal",3,"A patient with de Quervain tenosynovitis has a positive Finkelstein test. First-line treatment includes:",["Surgical release immediately","Thumb spica splint, NSAIDs, and corticosteroid injection","Opioid therapy","Physical therapy alone"],1,"De Quervain's (first extensor compartment tenosynovitis) responds to thumb spica splint (immobilization), NSAIDs, and corticosteroid injection into the tendon sheath. Finkelstein test (pain with ulnar deviation of the fist) is diagnostic. Surgery is for refractory cases."),
  np("AANP","Infectious Disease",3,"A patient with a cat bite to the hand should receive prophylactic antibiotics with:",["Cephalexin","Amoxicillin-clavulanate (covers Pasteurella multocida)","Azithromycin","Metronidazole"],1,"Cat bites have high infection rates (30-50%) because deep puncture wounds inoculate bacteria into deep tissue. Pasteurella multocida is the most common pathogen. Amoxicillin-clavulanate provides coverage for Pasteurella, anaerobes, and other oral flora."),
  np("NP-CAT","Reproductive",3,"A patient with recurrent pregnancy loss (3+ miscarriages) should be evaluated for:",["No workup needed until 5 miscarriages","Antiphospholipid syndrome, uterine anomalies, thyroid dysfunction, and karyotype of both partners","Genetic counseling only","Cervical cerclage without evaluation"],1,"Recurrent pregnancy loss workup: antiphospholipid antibodies (lupus anticoagulant, anticardiolipin, anti-beta2 glycoprotein), uterine evaluation (HSG or hysteroscopy), thyroid function, parental karyotype, and possibly thrombophilia screening."),
  np("AANP","Geriatrics",3,"An elderly patient with delirium should have which common reversible causes investigated first?",["Only brain imaging","Medications, infection (UTI), metabolic abnormalities, pain, and urinary retention","Psychiatric evaluation only","EEG as first test"],1,"Delirium workup focuses on reversible causes (mnemonic DELIRIUM): Drugs, Electrolytes, Lack of drugs (withdrawal), Infection, Reduced sensory input, Intracranial events, Urinary/fecal retention, Myocardial/pulmonary issues. UTI and medication changes are most common."),
  np("NP-CAT","Hematological",3,"A patient with unexplained thrombocytopenia (platelets 45,000) should have:",["Immediate platelet transfusion","Peripheral blood smear review and workup for ITP, TTP, HIT, and bone marrow disorders","No further evaluation if asymptomatic","Splenectomy"],1,"Thrombocytopenia workup: peripheral smear (schistocytes suggest TTP/HUS, large platelets suggest ITP), medication review (HIT screen if on heparin), HIV/HCV testing, autoimmune workup, and possible bone marrow biopsy if cause unclear."),
  np("AANP","Renal",3,"A patient with nephrolithiasis and uric acid stones should be managed with:",["Increasing calcium intake only","Urinary alkalinization with potassium citrate, allopurinol, and dietary purine restriction","Thiazide diuretics only","ESWL as first-line"],1,"Uric acid stones (the only radiolucent stones on plain X-ray) can be dissolved with urinary alkalinization (potassium citrate, target urine pH 6.5-7.0). Allopurinol reduces uric acid production. Low-purine diet and adequate hydration prevent recurrence."),
  np("AANP","Women's Health",3,"A patient with symptoms of perimenopause should be counseled that:",["FSH levels reliably confirm perimenopause","Perimenopause is diagnosed clinically based on symptoms; FSH levels fluctuate and are unreliable","Estrogen levels are always low in perimenopause","Menstruation stops abruptly"],1,"Perimenopause is a clinical diagnosis based on menstrual irregularity and vasomotor symptoms in appropriate age group (typically 45-55). FSH fluctuates widely and is not reliable for diagnosis. Menstruation becomes irregular before cessation."),
  np("NP-CAT","Women's Health",3,"A patient with vulvovaginal candidiasis that recurs 4 or more times per year should receive:",["Single-dose fluconazole each episode","Induction fluconazole regimen followed by weekly maintenance therapy for 6 months","Daily antifungal cream indefinitely","Oral metronidazole"],1,"Recurrent vulvovaginal candidiasis (>= 4 episodes/year) requires induction (fluconazole 150mg every 72 hours x 3 doses) then maintenance (fluconazole 150mg weekly for 6 months). Rule out contributing factors: diabetes, immunosuppression, antibiotic use."),
  np("AANP","Preventive Medicine",2,"The NP should recommend the pneumococcal vaccine series for adults age 65+ as:",["PCV20 alone or PCV15 followed by PPSV23","PPSV23 only","PCV13 followed by PPSV23 in all cases","No vaccination if previously healthy"],0,"Updated CDC guidelines (2021): adults >= 65 without previous pneumococcal vaccination should receive either PCV20 alone OR PCV15 followed by PPSV23 (at least 1 year later). Previous vaccination history guides specific recommendations."),

  // === More RPN ===
  rpn("REX-PN","Cardiovascular",3,"A client with aortic stenosis presents with syncope on exertion. The nurse should:",["Encourage exercise to improve cardiac function","Restrict activity and refer for valve evaluation as exertional syncope indicates severe stenosis","Administer nitrates for vasodilation","Increase fluid intake only"],1,"Exertional syncope is a red flag symptom of severe aortic stenosis indicating inadequate cardiac output during activity. Activity restriction and prompt evaluation for valve replacement are indicated. Vasodilators (nitrates) are relatively contraindicated."),
  rpn("REX-PN","Respiratory",3,"A client receiving aminoglycoside antibiotics and loop diuretics simultaneously is at increased risk for:",["Hepatotoxicity","Ototoxicity and nephrotoxicity due to synergistic toxicity","Cardiotoxicity","Skin reactions"],1,"Both aminoglycosides and loop diuretics are independently ototoxic and nephrotoxic. Combined use has synergistic toxicity. Monitor hearing (audiometry), vestibular function, BUN/creatinine, and drug trough levels closely."),
  rpn("REX-PN","Neurological",3,"A client with meningitis should be placed in which position?",["Flat with head turned to the side","Semi-Fowler's or side-lying with head slightly elevated to reduce ICP","Prone position","Trendelenburg position"],1,"Semi-Fowler's position (HOB elevated 30 degrees) reduces ICP by promoting venous drainage from the brain. Side-lying with HOB elevation prevents aspiration in altered consciousness. Dim lighting reduces photophobia-related discomfort."),
  rpn("REX-PN","Endocrine",3,"A client prescribed desmopressin (DDAVP) for central diabetes insipidus should monitor for:",["Hyperglycemia","Water intoxication and hyponatremia from excessive water retention","Hypernatremia","Dehydration"],1,"DDAVP replaces deficient ADH, promoting water reabsorption. Overdosage or excessive fluid intake while on DDAVP can cause water intoxication and dilutional hyponatremia, leading to cerebral edema, seizures, and potentially death."),
  rpn("REX-PN","Gastrointestinal",3,"A client with achalasia has difficulty swallowing both solids and liquids equally. This pattern is characteristic of:",["Mechanical obstruction (tumor)","Motility disorder (esophageal dysmotility)","GERD","Peptic stricture"],1,"Equal difficulty with solids AND liquids suggests a motility disorder. Mechanical obstruction typically presents with progressive solid food dysphagia first, then liquids as obstruction worsens. Achalasia involves failure of the LES to relax with absent esophageal peristalsis."),
  rpn("REX-PN","Pharmacology",3,"A client taking spironolactone should be instructed to avoid:",["Citrus fruits","Potassium supplements and salt substitutes (contain potassium chloride)","Calcium supplements","Magnesium supplements"],1,"Spironolactone is a potassium-sparing diuretic. Adding potassium supplements or salt substitutes (KCl) risks life-threatening hyperkalemia. Monitor serum potassium regularly. Dietary counseling about high-potassium foods is also important."),
  rpn("REX-PN","Mental Health",3,"When a client demonstrates 'loose associations' in speech, this refers to:",["Organized but slow speech","Shifting from one unrelated topic to another without logical connection","Speaking very rapidly","Repeating words obsessively"],1,"Loose associations are a thought process disorder where the client shifts between unrelated topics without awareness. There is no logical connection between ideas. This is common in schizophrenia and severe manic episodes."),
  rpn("REX-PN","Pediatrics",2,"A child's immunization schedule should be followed because vaccines:",["Are optional and provide no significant benefit","Provide protection against serious and potentially fatal childhood diseases","Are only needed for international travel","Are required only for school entry"],0,"Vaccines prevent serious childhood illnesses (measles, whooping cough, polio, etc.) that can cause disability or death. Following the CDC schedule ensures timely immunity development. Herd immunity protects those who cannot be vaccinated."),
  rpn("REX-PN","Fundamentals",2,"When administering medication through a gastrostomy tube, the nurse should:",["Crush all medications together and mix with tube feeding","Administer each medication separately, flushing with 15-30 mL water between medications","Mix all medications with milk","Push all medications through at once without flushing"],1,"Each medication is administered separately to prevent drug interactions and tube clogging. Flush with 15-30 mL warm water before, between, and after medications. Never crush extended-release or enteric-coated medications. Verify tube placement first."),
  rpn("REX-PN","Musculoskeletal",3,"A client with myasthenia gravis experiences ptosis and diplopia that worsen with activity and improve with rest. These symptoms indicate:",["Progressive, irreversible weakness","Fatigable weakness characteristic of myasthenia gravis","Permanent nerve damage","Central nervous system involvement"],1,"MG hallmark is fatigable weakness: symptoms worsen with activity (sustained use depletes acetylcholine at the NMJ) and improve with rest. Ocular symptoms (ptosis, diplopia) are often the earliest manifestation. Diagnosis confirmed by AChR antibodies and edrophonium test."),
  rpn("REX-PN","Renal",3,"A client with a ureteral stent should be taught that the stent may cause:",["No symptoms","Frequency, urgency, and flank pain especially with voiding, which are expected side effects","Only improved urinary flow","Permanent kidney damage"],1,"Ureteral stents commonly cause irritative voiding symptoms (frequency, urgency, dysuria), hematuria, and flank pain that worsens during voiding (ureteral reflux). Alpha-blockers (tamsulosin) may reduce stent-related symptoms."),
  rpn("REX-PN","Maternal/Newborn",2,"Exclusive breastfeeding is recommended for the first:",["2 months of life","6 months of life with continued breastfeeding to at least 12 months","12 months without any supplements","3 months before introducing solid foods"],1,"WHO and AAP recommend exclusive breastfeeding for 6 months with continued breastfeeding alongside complementary foods to 12 months and beyond. Benefits include optimal nutrition, immune protection, decreased infection, and improved maternal health."),
  rpn("REX-PN","Infection Control",2,"Hand hygiene with alcohol-based sanitizer is NOT effective against:",["Most bacteria","Most viruses","Clostridium difficile spores","Influenza virus"],2,"Alcohol-based hand sanitizers do not kill C. difficile spores. Soap and water hand washing is required when caring for patients with C. diff infection. Similarly, norovirus is poorly killed by alcohol-based sanitizers."),
  rpn("REX-PN","Hematological",3,"A client with chronic myelogenous leukemia (CML) is prescribed imatinib (Gleevec). The nurse should teach that this medication:",["Cures CML in all patients","Is a targeted therapy that inhibits the BCR-ABL tyrosine kinase produced by the Philadelphia chromosome","Is a traditional chemotherapy drug","Should only be taken for 6 months"],1,"Imatinib targets the BCR-ABL protein produced by the Philadelphia chromosome translocation (t(9;22)) in CML. It produces complete cytogenetic response in 80%+ of chronic phase patients. Treatment is typically lifelong with regular monitoring."),
  rpn("REX-PN","Integumentary",3,"A client with melanoma has a Breslow depth of 2.5mm. The nurse should understand this indicates:",["Low risk of metastasis","Intermediate risk requiring wide excision with 2cm margins and sentinel lymph node biopsy","A superficial, easily treated lesion","No need for further evaluation"],1,"Breslow depth of 2.5mm (intermediate thickness, 1-4mm) requires wide excision with 2cm margins and sentinel lymph node biopsy for staging. Five-year survival is approximately 80%. Regular follow-up with dermatological examinations is essential."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[RN-B2] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
